import "./DashboardCards.css";
import {
    FaUsers,
    FaCalendarCheck,
    FaMoneyCheckAlt,
    FaPlaneDeparture
} from "react-icons/fa";

const DashboardCards = () => {

    const cards = [
        {
            title: "Employees",
            value: 25,
            icon: <FaUsers />,
            color: "#2563eb"
        },
        {
            title: "Attendance",
            value: 22,
            icon: <FaCalendarCheck />,
            color: "#16a34a"
        },
        {
            title: "Leaves",
            value: 4,
            icon: <FaPlaneDeparture />,
            color: "#ea580c"
        },
        {
            title: "Payroll",
            value: "₹9.5 L",
            icon: <FaMoneyCheckAlt />,
            color: "#9333ea"
        }
    ];

    return (

        <div className="dashboard-cards">

            {

                cards.map((card, index) => (

                    <div
                        className="dashboard-card"
                        key={index}
                    >

                        <div
                            className="card-icon"
                            style={{
                                background: card.color
                            }}
                        >
                            {card.icon}
                        </div>

                        <div>

                            <h4>{card.title}</h4>

                            <h2>{card.value}</h2>

                        </div>

                    </div>

                ))

            }

        </div>

    );

};

export default DashboardCards;
